SELECT 'What to Expect at a Moreška Performance in Korčula', 'what-to-expect-moreska-performance-korcula', 'en'::enum_posts_locale, 'Planning to see the Moreška sword dance in Korčula? Here''s what a performance is really like, the story, the swords, the music, and how to get the best seats.',
  '/moreska-wide.webp', 'The two Moreška armies facing off with iron swords on the Summer Cinema stage in Korčula', '{"root":{"direction":"ltr","format":"","indent":0,"type":"root","version":1,"children":[{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"You have booked an evening in Korčula, you have heard there is a centuries-old sword dance, and now you want to know what you are actually walking into. This is the practical guide: what happens on stage, how long it lasts, what to wear, and how to make sure you get a good seat.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The short version: you are about to watch ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Europe''s last surviving authentic war dance","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", performed with real iron swords by the people of Korčula, exactly where it has been performed for generations. It is loud, it is physical, and it is unlike any folklore show you have seen before.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"What the Moreška actually is","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Moreška is not a re-enactment staged for tourists. It is a living tradition that traces back to the medieval \"Moros y Cristianos\" mock battles of the Mediterranean, the earliest recorded performance was in Lérida, Spain, in 1150, and it has been documented in Korčula since a town journal entry dated ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"7 March 1666","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":". As the same war dances faded from every other town on the Dalmatian coast, Korčula became the last place where the authentic form survived.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Today it is officially recognised as a ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"protected cultural good of the Republic of Croatia","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", and it is staged by ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/about"},"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"HGD Sveta Cecilija","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":", the cultural society that has been its guardian since 1883.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The story you''ll be watching","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Moreška is a drama as much as a dance. Two kings fight over one woman.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Bula","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", a young woman, has been taken by force by ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Moro, the Black King","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":". The ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"White King, Osman","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", her betrothed, arrives to win her back. The Bula refuses to yield to her captor: ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"\"All I ask of you… far more pain for me is your unwanted love than the steel.\"","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" What follows is a challenge, and then seven escalating sword battles to decide her fate.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The dialogue is spoken in an ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"archaic 17th-century Korčulan dialect","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", so you will not understand every word even if you speak Croatian, and that is fine. The story is told in the bodies, the swords and the music. (If you want the plot in your own language, ask at the entrance: a short program guide is usually available, and we recommend it.)","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h3","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The shape of the evening","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"A typical performance unfolds in three parts:","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"list","listType":"number","start":1,"tag":"ol","version":1,"children":[{"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"The opening","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", the evening usually begins with ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/sections/klapa"},"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Klapa Sveta Cecilija","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":", a male a cappella ensemble singing traditional Dalmatian song, and the live ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/sections/wind-orchestra"},"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Wind Orchestra","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":". This is your moment to settle in.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"The drama","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", the spoken confrontation between the kings and the Bula sets up the conflict.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"The dance","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", the seven ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"kolapi","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" (sword-clash figures), each faster and fiercer than the last, ending in the surrender of the Black King and the freeing of the Bula.","type":"text","version":1}]}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Plan for an evening of roughly an hour end to end. The combat itself is the climax, so if the opening songs feel slow, stay with it; the payoff is worth it.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The part everyone remembers: the swords","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"This is what sets the Moreška apart from any other folk dance in Europe. Every dancer wields ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"two iron swords","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", the right hand strikes, the left parries. Each blade weighs about a kilogram, and they are real.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"When the armies clash, the swords strike hard enough to throw sparks, and the sound, ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"bam, bam, bam","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", rings off the stone walls of the old town. It is genuinely percussive; you feel it as much as hear it. The choreography is fixed and has been passed down unchanged for generations: seven figures named Rugier, Moreška, Finta, Moro in dentro, Križ (the Cross), Rugier de fuorivia, and the furious Final Figure danced at full speed.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"This is also why the front row comes with a gentle warning: you are close to real steel. The dancers are highly trained and strike with precision, but the first rows are an immersive, occasionally intense place to sit. If you are bringing small children or you would simply rather take it all in from a calmer vantage point, a few rows back is perfect.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Practical tips for your visit","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"list","listType":"bullet","start":1,"tag":"ul","version":1,"children":[{"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Showtime is 21:00.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" Performances run on selected evenings through the season, check the current ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/tickets"},"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"performance schedule and book tickets","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":" before you go, as dates vary week to week.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Arrive early for the best seats.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" This is the single most common piece of advice from past visitors. Seating is not numbered, so the earlier you arrive, the more choice you have. Aim for 20–30 minutes before the start.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"The venue is the Summer Cinema (Ljetno kino),","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" an open-air stage in the old town. It is tucked into the historic streets, so give yourself a few extra minutes to find it the first time.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Dress comfortably.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" Summer evenings in Korčula are warm but the open-air setting can cool down after sunset, a light layer is a good idea.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":5,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Tickets:","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" €20 for adults, €10 for children under 14. Groups get every fifth ticket free. (More on bringing children in our guide, ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/blog/is-moreska-suitable-for-kids"},"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Is Moreška Suitable for Kids?","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":")","type":"text","version":1}]}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Why it''s worth it","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Plenty of destinations offer a \"traditional show.\" Very few offer something that has genuinely never stopped, performed by the same community, in the same place, with the same iron, for centuries. The Moreška is not a performance ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"about","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" Korčula''s history; it is a piece of that history, still happening.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Come for the swords. Stay for the realisation that you are watching something almost nowhere else on earth can offer.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/tickets"},"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"See the 2026 schedule and book your tickets →","type":"text","version":1}],"direction":"ltr","format":"","indent":0}]}]}}'::jsonb,
  '2026-07-15T09:00:00Z'::timestamptz, 'published'::enum_posts_status
WHERE NOT EXISTS (SELECT 1 FROM posts WHERE slug = 'what-to-expect-moreska-performance-korcula' AND locale = 'en');

INSERT INTO posts (title, slug, locale, excerpt, hero_image, hero_image_alt, body, published_at, status)
SELECT 'Povijest Moreške: 400 godina plesa s mačevima', 'povijest-moreske-ples-s-macevima', 'hr'::enum_posts_locale, 'Od španjolske bitke iz 12. stoljeća do kamenih ulica Korčule, povijest Moreške, posljednjeg sačuvanog autentičnog ratnog plesa Europe, i kako je opstala.',
  '/cecilija-est.webp', 'Povijesna fotografija vezana uz HGD Sveta Cecilija, čuvara Moreške od 1883. godine', '{"root":{"direction":"ltr","format":"","indent":0,"type":"root","version":1,"children":[{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Moreška koju večeras možete pogledati u Korčuli posljednja je svoje vrste. Slični plesovi s mačevima nekoć su se izvodili diljem Sredozemlja, od Španjolske do Sicilije, od Venecije do grčkih otoka. Danas je jedino korčulanska sačuvana u cijelosti. Ovo je priča o tome kako je srednjovjekovni borbeni ritual prešao cijelo more i pronašao svoj konačni dom na jednom hrvatskom otoku.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Ples rođen iz osvajanja","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Moreška je u svojoj srži „ples osvajanja\", stilizirani prikaz srednjovjekovnog sukoba kršćanske Europe i islamskoga svijeta. Pripada široj sredozemnoj tradiciji insceniranih bitaka ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"Moros y Cristianos","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" („Mauri i kršćani\"). Najraniji zabilježeni nastup odvio se u ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Lleidi, u Španjolskoj, 1150. godine","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", u spomen na kršćansko osvajanje Aragona.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Odatle se oblik širio trgovačkim putovima Sredozemlja. Do Jadrana je stigao u 16. stoljeću, premda neki znanstvenici njegov utjecaj prepoznaju već u plesu s mačevima zabilježenom u ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Trogiru 1273. godine","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":".","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Kako je stigla do Korčule","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Moreška je do Korčule stigla morem. Trgovački putovi povezivali su otok sa Sicilijom, južnom Italijom i Španjolskom, a ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"od 1420. grad je gotovo četiri stoljeća bio mletački posjed","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", što je u lokalni život slijevalo talijanske i španjolske kulturne oblike.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Do sredine 17. stoljeća ples je bio utkan u tkivo grada. Prvi nedvojbeni pisani zapis o izvedbi Moreške u Korčuli zapis je u gradskom dnevniku ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"datiran 7. ožujka 1666.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", koji opisuje karnevalski događaj. Drugdje na obali tradicija se već povlačila: čuvena inscenirana bitka izvedena je u ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Splitu u rujnu 1571.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" u slavu pobjede nad Osmanlijama kod Lepanta, no kako je prijetnja invazijom jenjavala, ti su plesovi nestajali iz grada za gradom. Korčula je postala ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"posljednje uporište","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" autentičnog ratnog plesa.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Zašto je opstala samo ovdje?","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Povjesničari i etnokoreolozi dugo se pitaju zašto je baš Korčula ustrajala. Jedinstvenog odgovora nema, no ističu se tri objašnjenja:","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"list","listType":"bullet","start":1,"tag":"ul","version":1,"children":[{"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Vojna priprema.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" Maloj otočkoj posadi koju su često napadali gusari i osmanski pljačkaši ples je služio i kao „tjelovježba\" i vježba mačevanja, održavajući mještane spremnima s teškim željeznim oštricama.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"„Skriveni govor\" otpora.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" Znanstvenici poput Maxa Harrisa i Lade Čale Feldman tvrde da je ples Korčulanima omogućavao prikriveni izraz prkosa stranoj vlasti, javna je priča bila pobjeda kršćana nad Maurima, no ritualna je borba dopuštala sigurniji, metaforički otpor mletačkoj ili drugoj vlasti.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Društvena povezanost.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" Čvrsto ustrojen sustav bratovština, poput bratovštine Svih svetih, osnovane još 1301., dao je gradu stabilnost potrebnu da se složena koreografija prenosi s naraštaja na naraštaj. Ples je postao obred prijelaza, predavan s oca na sina.","type":"text","version":1}]}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Kralj, nošnja i kraljevski svjedok","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Do 19. stoljeća Moreška je poprimila oblik koji danas prepoznajemo, s „Bijelom\" i „Crnom\" vojskom te prepoznatljivim ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"„rimsko-orijentalnim\" nošnjama","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", koje su putnici prvi put opisali početkom 1800-ih, a vjerojatno potječu od talijanskih dvorskih baletnih kostima iz 17. stoljeća. Imamo čak i kraljevskog svjedoka: ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"1838. saksonski je kralj Fridrik August II. gledao izvedbu","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", ostavivši neke od najranijih opisa nošnji.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"1883.: društvo koje će čuvati ples","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Prekretnica za modernu Morešku dogodila se ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"1883.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", u doba hrvatskoga narodnog preporoda, kada su mještani osnovali korčulansko pjevačko društvo Sv. Cecilije, današnji ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"HGD Sveta Cecilija","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":". Njegova su pravila postavila „plemenitu i uzvišenu svrhu\": „oplemeniti srca domaće mladeži\" hrvatskom narodnom pjesmom i jezikom. Društvo je postalo institucionalni dom Moreške i najstarije je građansko pjevačko društvo u južnoj Hrvatskoj. Više o društvu pročitajte na ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/about"},"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"stranici o nama","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":".","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Drugi se ključni trenutak dogodio ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"1937.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", kada je ugledni hrvatski skladatelj ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Krsto Odak","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", u suradnji s dirigentom ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Josipom Svobodom","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", napisao konačnu partituru za limenu glazbu, sedam stavaka koji se uzdižu od lirskih tema do mahnitog finala. Ta se obrada izvodi na svakom nastupu od 1947., i upravo je to glazba koju i danas čujete.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Rat, pepeo i obnova","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Dvadeseto je stoljeće tradiciju gotovo prekinulo dvaput.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Drugi svjetski rat","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" ušutkao je društvo. Nošnje, željezni mačevi i partiture izgubljeni su ili uništeni u borbama. No ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"1944., dok se kraj oslobađao","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", gradski brijač ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Ivo Lozica","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", zapamćen kao „neumorni duh\", i učitelj ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Božo Jeričević","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" od nule su uvježbali posve novu skupinu dječaka u dobi od 12 do 17 godina. Nošnje su improvizirane; koordinator Bernard Maroević čak je pomogao nabaviti tkaninu s crkvenih oltara za odjeću plesača. Tradicija nije umrla.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Kroz socijalističke jugoslavenske naraštaje ples se nastavio pod različitim organizacijskim okriljima, predstavljajući Korčulu i u inozemstvu, uključujući ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Svjetski festival mladih u Pragu 1947.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" Potom je, nakon proglašenja hrvatske neovisnosti, ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"HGD Sveta Cecilija službeno obnovljen 1991.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" pod svojim izvornim imenom i poslanjem.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Moreška danas","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Društvo danas broji oko 150 članova i djeluje kroz tri sekcije: ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"moreškantsku družinu","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/sections/wind-orchestra"},"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Puhački orkestar","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":" i ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/sections/klapa"},"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Klapu Sveta Cecilija","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":". Nekoć izvođena samo jednom godišnje na ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"29. srpnja, blagdan sv. Todora","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", raskošna izvedba koja je znala trajati dva sata, Moreška se sada izvodi kroz cijelu ljetnu sezonu kako bi je posjetitelji mogli doživjeti. Korčula je 1997. čak pokrenula Festival viteških igara i plesova s mačevima.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Moreška je danas ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"zaštićeno kulturno dobro Republike Hrvatske","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":". Gotovo devet stoljeća nakon one prve inscenirane bitke u Španjolskoj, ista se drama i dalje odvija na kamenoj pozornici u Korčuli, dvije vojske, željezni mačevi i zajednica koja nije dopustila da njezin ples umre.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/tickets"},"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Doživite je uživo, kupite ulaznice za sezonu 2026. →","type":"text","version":1}],"direction":"ltr","format":"","indent":0}]}]}}'::jsonb,
  '2026-11-15T09:00:00Z'::timestamptz, 'published'::enum_posts_status
WHERE NOT EXISTS (SELECT 1 FROM posts WHERE slug = 'povijest-moreske-ples-s-macevima' AND locale = 'hr');

INSERT INTO posts (title, slug, locale, excerpt, hero_image, hero_image_alt, body, published_at, status)
SELECT 'The History of Moreška: 400 Years of Sword Dance in Korčula', 'history-of-moreska-sword-dance', 'en'::enum_posts_locale, 'From a 12th-century Spanish battle to the stone streets of Korčula, the history of the Moreška, Europe''s last surviving authentic sword dance, and how it endured.',
  '/cecilija-est.webp', 'Historic photograph connected to HGD Sveta Cecilija, guardian of the Moreška sword dance since 1883', '{"root":{"direction":"ltr","format":"","indent":0,"type":"root","version":1,"children":[{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Moreška you can watch in Korčula tonight is the last of its kind. Sword dances like it once spanned the Mediterranean, from Spain to Sicily, from Venice to the Greek islands. Today, only Korčula''s survives intact. This is the story of how a medieval battle ritual travelled across an entire sea and found its final home on one Croatian island.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"A dance born from conquest","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Moreška is, at its root, a \"dance of conquest\", a stylised retelling of the medieval struggle between Christian Europe and the Islamic world. It belongs to the wider Mediterranean tradition of ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"Moros y Cristianos","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" (\"Moors and Christians\") mock battles. The earliest recorded performance took place in ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Lérida, Spain, in 1150","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", commemorating the Christian capture of Aragon and staging a mock combat between two armies.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"From there the form spread along the trade routes of the Mediterranean. It reached the Adriatic by the 16th century, though some scholars trace its influence as far back as a sword dance reported in ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Trogir in 1273","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":".","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"How it reached Korčula","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Moreška arrived in Korčula by sea. Trade routes linked the island to Sicily, Southern Italy and Spain, and from ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"1420 the town spent nearly four centuries as a Venetian outpost","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", a status that funnelled Italian and Spanish cultural forms into local life.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"By the mid-17th century the dance was woven into the fabric of the town. The first unambiguous written record of a Moreška performance in Korčula is a ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"journal entry dated 7 March 1666","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", describing a carnival event. Elsewhere on the coast the tradition was already in retreat: a famous staged battle had been performed in ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Split in September 1571","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" to celebrate the victory over the Ottomans at Lepanto, but as the threat of invasion receded, these dances disappeared from town after town. Korčula became the ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"final bastion","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" of the authentic war-dance form.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Why did it survive only here?","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Historians and ethnochoreologists have long asked why Korčula, of all places, held on. There is no single answer, but three explanations stand out:","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"list","listType":"bullet","start":1,"tag":"ul","version":1,"children":[{"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Martial preparation.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" For a small island garrison frequently targeted by pirates and Ottoman raiders, the dance doubled as a \"keep-fit class\" and sword practice, keeping local men physically capable with heavy iron blades.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"A \"hidden transcript\" of resistance.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" Scholars such as Max Harris and Lada Čale Feldman argue the dance let Korčulans express a coded defiance of their foreign rulers, the public story was Christians defeating Moors, but the ritual combat allowed a safer, metaphorical resistance against Venetian or other authority.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Social cohesion.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" Korčula''s tightly organised system of guilds and brotherhoods, like the All Saints brotherhood, founded as far back as 1301, gave the town the institutional stability to pass complex choreography from one generation to the next. The dance became a rite of passage, handed from father to son.","type":"text","version":1}]}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"A king, a costume, a king''s witness","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"By the 19th century the Moreška had acquired the form we recognise today, with its \"White\" and \"Black\" armies and its distinctive ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"\"Roman-Oriental\" costumes","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", first described by travellers in the early 1800s and likely descended from 17th-century Italian court-ballet costume. We even have a royal eyewitness: in ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"1838 the Saxon King Frederick Augustus II witnessed a performance","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", leaving behind some of the earliest descriptions of the costumes.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"1883: a society to guard the dance","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The turning point for the modern Moreška came in ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"1883","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", during the Croatian National Revival, when local citizens founded the Korčula Singing Society St. Cecily, today''s ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"HGD Sveta Cecilija","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":". Its statutes set out a \"noble and lofty purpose\": to \"ennoble the hearts of the local youth\" through Croatian folk song and language. The society became the institutional home of the Moreška, and remains the oldest civic singing society in Southern Croatia. You can read more about the organisation on our ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/about"},"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"about page","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":".","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"A second milestone followed in ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"1937","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", when the renowned Croatian composer ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Krsto Odak","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", working with conductor ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Josip Svoboda","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", wrote the definitive brass-band score, seven movements building from lyrical themes to a furious finale. That arrangement has been used at every performance since 1947, and it is the music you still hear today.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"War, ashes, and revival","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The 20th century nearly broke the tradition twice.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Second World War","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" silenced the society. Costumes, iron swords and musical scores were lost or destroyed in the fighting. But in ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"1944, as the region was being liberated","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", the town barber ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Ivo Lozica","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", remembered as an \"indefatigable spirit\", and the schoolteacher ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Božo Jeričević","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" trained an entirely new troop of teenage boys, aged 12 to 17, from scratch. Costumes were improvised; the coordinator Bernard Maroević even helped procure fabric from church altars to clothe the dancers. The tradition did not die.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Through the socialist Yugoslav decades the dance continued under different organisational banners, even representing Korčula abroad, including at the ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"1947 World Youth Festival in Prague","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":". Then, after Croatia''s declaration of independence, ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"HGD Sveta Cecilija was officially re-established in 1991","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" under its original name and mission.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Moreška today","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The society now numbers around 150 members and runs three sections: the ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Moreška Troop","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", the ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/sections/wind-orchestra"},"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Wind Orchestra","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":", and ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/sections/klapa"},"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Klapa Sveta Cecilija","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":". Once performed only once a year on ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"29 July, the Feast of St. Theodore","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", a lavish presentation that could run two hours, the Moreška now plays through the summer season so visitors can experience it. In 1997 Korčula even launched a Sword Dance Festival, gathering the island''s related traditions in one place.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Moreška is now a ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"protected cultural good of the Republic of Croatia","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":". Nearly nine centuries after that first mock battle in Spain, the same drama still plays out on a stone stage in Korčula, two armies, fourteen iron swords, and a community that refused to let its dance die.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/tickets"},"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"See it for yourself, book tickets for the 2026 season →","type":"text","version":1}],"direction":"ltr","format":"","indent":0}]}]}}'::jsonb,
  '2026-11-15T09:00:00Z'::timestamptz, 'published'::enum_posts_status
WHERE NOT EXISTS (SELECT 1 FROM posts WHERE slug = 'history-of-moreska-sword-dance' AND locale = 'en');

INSERT INTO posts (title, slug, locale, excerpt, hero_image, hero_image_alt, body, published_at, status)
SELECT 'Is Moreška Suitable for Kids? A Parent''s Guide', 'is-moreska-suitable-for-kids', 'en'::enum_posts_locale, 'Thinking of bringing children to the Moreška sword dance in Korčula? A straight-talking guide to ages, noise, real swords, seating, runtime and child tickets.',
  '/younglings.webp', 'Young Moreška dancers in costume in Korčula, learning the centuries-old sword dance', '{"root":{"direction":"ltr","format":"","indent":0,"type":"root","version":1,"children":[{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Short answer: ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"yes, and many children love it.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" The Moreška is a live sword dance with a clear hero-and-villain story, dramatic music and genuinely thrilling combat. For a lot of kids it''s the highlight of their trip to Korčula. But there are a few honest things worth knowing before you book, so you can choose the right seats and set expectations. Here''s the practical rundown.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"What kids actually see","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Moreška tells a story any child can follow even without understanding the words: a young woman, the ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Bula","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", has been captured by the ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Black King","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", and the ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"White King","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" comes to rescue her. After a tense confrontation, the two armies fight seven escalating sword battles, and good wins. The Bula is freed, the villain surrenders his sword. It''s a fairy-tale shape, told with real drama.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The dialogue is spoken in an old Korčulan dialect, so neither you nor your children will catch every word, but the story plays out so vividly in the action that it doesn''t matter. Pointing out \"that''s the hero, that''s the king who took her, watch what happens\" is usually all the setup a child needs.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The honest part: it''s loud, and the swords are real","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"This is what makes the Moreška special, and it''s exactly what to factor in for younger children.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"list","listType":"bullet","start":1,"tag":"ul","version":1,"children":[{"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"The swords are real iron.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" Each dancer carries two blades weighing about a kilogram, and they strike hard enough to throw sparks. The clashing is rhythmic and forceful, ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"bam, bam, bam","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" echoing off the old town''s stone walls.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"It''s genuinely loud,","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" between the live brass orchestra and the metal-on-metal combat. Most school-age children find this exciting; sound-sensitive toddlers may find it a lot.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"The front rows are immersive.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" Sitting close puts you right up against the action and real steel. The dancers are highly trained and strike with precision, but for families we''d usually suggest sitting ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"a few rows back","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", you get the full spectacle with a calmer vantage point and a clear view over the crowd.","type":"text","version":1}]}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"None of this is a reason to leave the kids at home. It''s a reason to pick your seats deliberately.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"What age is best?","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"There''s no official age limit, and Korčula''s own children grow up with this dance, boys here begin learning the steps in ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"elementary school","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", and the troupe has long trained dancers from age 12. As a rough guide for visitors:","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"list","listType":"bullet","start":1,"tag":"ul","version":1,"children":[{"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Ages roughly 6 and up","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" tend to be the sweet spot: old enough to follow the story, enjoy the swordplay, and handle the noise.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Younger children (3–5)","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" can absolutely enjoy it too, especially the music and the spectacle, just sit further back, and be ready to step out if the volume is too much.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Babies and toddlers:","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" the noise and a roughly hour-long, late-evening start time are the main considerations (see below).","type":"text","version":1}]}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"You know your own child best, this is a thrilling live show, not a quiet museum visit.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Timing: it''s a late, ~1-hour evening","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Performances begin at ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"21:00","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":". The full evening, opening songs from the ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/sections/klapa"},"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"klapa","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":" and live ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/sections/wind-orchestra"},"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"wind orchestra","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":", the spoken drama, then the seven sword battles, runs roughly an hour. The combat is the climax, so the most exciting part comes toward the end.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"For families that means: a later night than usual, with the payoff arriving in the second half. If you have an early-to-bed little one, weigh that up. For most children the late start is part of the adventure, an open-air evening in a floodlit medieval town is a memory in itself.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Tickets, prices and seating tips","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"list","listType":"bullet","start":1,"tag":"ul","version":1,"children":[{"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Children under 14 are €10; adults are €20.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" Groups get every fifth ticket free (a nice saving for extended families travelling together).","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Seating is not numbered","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", so for families, arriving ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"20–30 minutes early","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" is the single best tip. It lets you choose seats a few rows back with a clear sightline, rather than taking whatever''s left.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The venue is the open-air ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Summer Cinema (Ljetno kino)","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" in the old town; give yourself a little extra time to find it.","type":"text","version":1}]}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Want the full picture before you decide? Read our companion guide, ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/blog/what-to-expect-moreska-performance-korcula"},"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"What to Expect at a Moreška Performance","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":", and learn more ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/about"},"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"about HGD Sveta Cecilija","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":", the society that has performed this dance since 1883.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The verdict","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"For curious, school-age children, the Moreška is close to ideal: a real story, real swords, real music, and a 400-year-old tradition unfolding in front of them. For toddlers, it can work beautifully from a few rows back, just go in knowing it''s loud and it''s late. Choose your seats, set the scene, and let them watch good defeat evil with iron and sparks.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/tickets"},"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Check 2026 dates and book your family''s tickets →","type":"text","version":1}],"direction":"ltr","format":"","indent":0}]}]}}'::jsonb,
  '2026-08-15T09:00:00Z'::timestamptz, 'published'::enum_posts_status
WHERE NOT EXISTS (SELECT 1 FROM posts WHERE slug = 'is-moreska-suitable-for-kids' AND locale = 'en');

INSERT INTO posts (title, slug, locale, excerpt, hero_image, hero_image_alt, body, published_at, status)
SELECT 'Moreška vs Kumpanjija: Korčula''s Two Sword Dances Explained', 'moreska-vs-kumpanjija-korcula-sword-dances', 'en'::enum_posts_locale, 'Korčula island is home to two living sword dances, the Moreška of Korčula town and the Kumpanjija of the villages. Here''s how they differ, honestly explained.',
  '/todor-2-vojske.webp', 'The two opposing armies of the Moreška sword dance assembled in Korčula', '{"root":{"direction":"ltr","format":"","indent":0,"type":"root","version":1,"children":[{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Korčula is unusual. Most places would be lucky to have one living sword dance; this single island has kept several alive. If you''ve been researching a visit, you''ve probably run into two names, the ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Moreška","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" and the ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Kumpanjija","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", and wondered whether they''re the same thing, or which one to see. Here''s an honest explanation of how they relate, and how they differ.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"One island, a treasure chest of sword dances","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The island of Korčula has been described as a \"unique treasure chest\" of European martial heritage, because more than one sword-dance tradition survives here. In ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"1997 the Korčula Tourist Board launched a Sword Dance Festival","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" specifically to bring these traditions together in one place, including the Moreška of Korčula town and the ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Kumpanjija","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" and ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Moštra","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" of the island''s villages, such as ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Žrnovo, Blato and Vela Luka","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":".","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"So the simplest way to understand it: ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"the Moreška is the sword dance of Korčula town; the Kumpanjija is the sword-dance tradition of the island''s villages.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" They are cousins, not rivals, two branches of the same island''s deep relationship with the dancing blade.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"What the Moreška is","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Moreška is the more theatrically elaborate of the two, and it''s the one staged in Korčula town by ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/about"},"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"HGD Sveta Cecilija","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":". Its defining features are well documented:","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"list","listType":"bullet","start":1,"tag":"ul","version":1,"children":[{"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"It''s a drama as well as a dance.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" There''s a written story, two kings, ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Moro","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" (the Black King) and ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Osman","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" (the White King), fight over a captured young woman, the ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Bula","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", performed in archaic 17th-century Korčulan verse before the fighting begins.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"It uses a double-sword technique.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" Every dancer wields ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"two","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" iron blades, the right hand striking and the left parrying, a feature that sets the Moreška apart from most European sword dances.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Seven named figures.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" The combat unfolds in seven named ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"kolapi","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", escalating in tempo to a furious finale, accompanied by a ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"brass-band score composed by Krsto Odak in 1937","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":".","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"A Mediterranean pedigree.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" The Moreška belongs to the ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"Moros y Cristianos","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" (\"Moors and Christians\") tradition, traceable to a performance in Lérida, Spain, in 1150, and documented in Korčula since 1666.","type":"text","version":1}]}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"It is recognised as a ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"protected cultural good of the Republic of Croatia","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", and Korčula is the last place where this authentic war-dance form survived intact. You can read its full story in our ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/blog/history-of-moreska-sword-dance"},"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"history of the Moreška","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":".","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"What the Kumpanjija is","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Kumpanjija is the sword-dance tradition of Korčula''s villages. Our own historical sources confirm what''s stated above, that it is a distinct island sword dance performed in places like Žrnovo, Blato and Vela Luka, but they don''t go into detail about how it''s choreographed.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"quote","version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"A note on accuracy:","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" Beyond \"it''s a village sword-dance tradition distinct from the town''s Moreška,\" the finer points below reflect ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"general descriptions","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" of the Kumpanjija rather than our own verified society records. If you want the authoritative account, the local cultural societies of Blato, Žrnovo, Vela Luka, Pupnat, Smokvica and Čara are the people to ask.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"In broad terms, visitors and ethnographers commonly describe the Kumpanjija as differing from the Moreška in a few ways: it tends to centre on a single linked or \"chain\" sword formation rather than the Moreška''s twin blades and elaborate two-king drama, and it''s traditionally bound up with village ceremony and identity rather than a scripted theatrical plot. The exact form varies from village to village, which is part of its charm.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Which should you see?","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"For most visitors to ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Korčula town","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", the answer is straightforward: the ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Moreška","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" is the one performed regularly through the summer season at the open-air Summer Cinema, with live music, full costume and the seven-battle drama. It''s the most accessible to plan around, and it''s the dance with the documented 400-year town pedigree.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If you''re travelling deeper into the island, to Blato, Žrnovo or Vela Luka, and your visit happens to coincide with a village celebration, seeking out the Kumpanjija is a wonderful, more local experience. The two aren''t an either/or so much as two doors into the same remarkable island culture.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The bottom line","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Korčula didn''t keep ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"a","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" sword dance alive, it kept a whole family of them. The ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Moreška","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" is the town''s theatrical, twin-sword, brass-scored war dance, performed since at least 1666 and guarded by HGD Sveta Cecilija since 1883. The ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Kumpanjija","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" is its village cousin. Seeing the Moreška is the easiest way to experience this heritage on a typical Korčula visit, and once you understand there''s a wider tradition behind it, the whole island starts to look like the living museum it genuinely is.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/tickets"},"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"See the Moreška this season, check dates and book →","type":"text","version":1}],"direction":"ltr","format":"","indent":0}]}]}}'::jsonb,
  '2026-10-15T09:00:00Z'::timestamptz, 'published'::enum_posts_status
WHERE NOT EXISTS (SELECT 1 FROM posts WHERE slug = 'moreska-vs-kumpanjija-korcula-sword-dances' AND locale = 'en');

INSERT INTO posts (title, slug, locale, excerpt, hero_image, hero_image_alt, body, published_at, status)
SELECT 'What to Do in Korčula in the Evening', 'what-to-do-in-korcula-in-the-evening', 'en'::enum_posts_locale, 'How to spend an evening in Korčula''s old town, sunset walks, the waterfront, dinner, and the one experience you can''t get anywhere else: the Moreška sword dance.',
  '/torches.webp', 'Korčula old town lit at night, the setting for the open-air Moreška sword dance', '{"root":{"direction":"ltr","format":"","indent":0,"type":"root","version":1,"children":[{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Korčula is beautiful by day, but the old town comes into its own after sunset. The crowds thin, the limestone streets glow gold under the lamps, and the sea air cools just enough to make a long evening outdoors a pleasure. If you''ve got a free night and you''re wondering how to fill it, here''s a relaxed way to spend an evening in town, built around the one thing you genuinely can''t experience anywhere else.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Start with the golden hour","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Korčula''s old town sits on a small peninsula, so you''re never far from water, and that makes it one of the best places on the Dalmatian coast to watch the sun go down. Find a spot on the western edge of the peninsula or along the waterfront promenade as the light softens. The fishbone street plan of the medieval town, laid out to catch the breeze and block the wind, is worth a slow wander while the sky changes colour.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"This is also the easiest hour to appreciate the architecture: the compact, fortified core, the towers, and the narrow stone lanes that open suddenly onto the water.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Wander the old town","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Once the sun is down, just walk. The old town is small enough to explore on foot in an evening, and atmospheric enough that you won''t want to rush. Highlights to look out for include the central cathedral and the tight network of stone streets and stairways that have barely changed in centuries. Korčula also famously claims a connection to the explorer ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Marco Polo","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", you''ll see his name around town, which makes for a fun thread to follow as you walk.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"quote","version":1,"children":[{"detail":0,"format":2,"mode":"normal","style":"","text":"Editor''s note: keep landmark and \"claim to Marco Polo\" references light and confirm details locally, see the README verification notes. We deliberately don''t recommend specific bars or restaurants here, to keep the post evergreen and neutral; HGD can curate named suggestions if desired.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Dinner, Dalmatian style","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Evening in Dalmatia is unhurried, and dinner is the centre of it. The old town and the waterfront are dotted with ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"konobas","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" (traditional taverns) and restaurants serving local seafood, island wine and Dalmatian classics. There''s no need to plan this to the minute, part of the pleasure is choosing a table with a view of the water and letting the evening stretch.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"A tip on timing: if you''re planning to catch the Moreška (more on that below), it begins at 21:00, so either eat earlier or save the long, lingering dinner for afterwards.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The one unmissable evening: the Moreška","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Here''s the experience that turns a nice evening in Korčula into a memorable one, and the reason many visitors plan their night around a specific date.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Moreška","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" is a 400-year-old sword dance, performed live in the open-air ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Summer Cinema","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" in the heart of the old town. It is ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Europe''s last surviving authentic war dance","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":": two armies, real iron swords, a dramatic story of a captured woman and the king who comes to free her, and a live brass orchestra driving seven escalating battles to a furious finale. The swords are real and strike hard enough to throw sparks, the sound rings off the stone walls of the town.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"It''s performed on selected evenings through the season, and it''s exactly the kind of thing an evening in a medieval Adriatic town should contain: dramatic, loud, rooted in centuries of local identity, and impossible to replicate anywhere else. The performance has been staged by ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/about"},"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"HGD Sveta Cecilija","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":", the island''s cultural society, since 1883.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If your evening in Korčula coincides with a performance, this is the thing to build the night around. Have an early dinner, take your sunset walk, then arrive 20–30 minutes before the 21:00 start to get a good seat (seating isn''t numbered, and the earlier you arrive, the better your view).","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/tickets"},"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Check which evenings the Moreška is performed and book tickets →","type":"text","version":1}],"direction":"ltr","format":"","indent":0}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"A simple evening plan","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If you want it as a recipe:","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"list","listType":"number","start":1,"tag":"ol","version":1,"children":[{"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"~19:00","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", sunset walk along the waterfront and through the old town.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"~19:30","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", early dinner at a konoba, or a drink with a view.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"~20:30","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", stroll to the Summer Cinema and grab a good seat.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":4,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"21:00","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", the Moreška: swords, music, and the most dramatic hour of your trip.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":5,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"~22:00","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", a late dessert or nightcap in the lamplit streets.","type":"text","version":1}]}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Korčula''s evenings reward people who slow down. Walk a little, eat well, and if the dates line up, let 400 years of clashing iron be the centrepiece. Curious what the show is actually like? Read ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/blog/what-to-expect-moreska-performance-korcula"},"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"what to expect at a Moreška performance","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":".","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/tickets"},"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"See the 2026 performance schedule →","type":"text","version":1}],"direction":"ltr","format":"","indent":0}]}]}}'::jsonb,
  '2026-09-15T09:00:00Z'::timestamptz, 'published'::enum_posts_status
WHERE NOT EXISTS (SELECT 1 FROM posts WHERE slug = 'what-to-do-in-korcula-in-the-evening' AND locale = 'en');

INSERT INTO posts (title, slug, locale, excerpt, hero_image, hero_image_alt, body, published_at, status)
SELECT 'Iza kulisa: upoznajte moreškante', 'iza-kulisa-moreskanti', 'hr'::enum_posts_locale, 'Tko su ljudi iza korčulanskog plesa s mačevima? Upoznajte moreškante, plesače koji mjesecima vježbaju, nose pravo željezo i nose tradiciju staru 400 godina.',
  '/moreskanti-cool.webp', 'Moreškanti u punoj nošnji u Korčuli', '{"root":{"direction":"ltr","format":"","indent":0,"type":"root","version":1,"children":[{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Kada gledate Morešku, vidite dvije vojske, četrnaest bljeskajućih mačeva i priču o ljubavi i borbi. Ono što ne vidite jest sve iza toga: mjeseci vježbe, obiteljske loze i tihi ponos zajednice koja ovaj ples stoljećima predaje s naraštaja na naraštaj. Upoznajte ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"moreškante","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", ljude koji održavaju korčulanski ples s mačevima živim.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Nisu glumci, Korčulani su","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Prvo što treba razumjeti jest da Morešku ne izvodi gostujuća družina. Izvode je ljudi Korčule. Ples je tradicionalno bio domena domaćih muškaraca iz korčulanskih obitelji i toliko je duboko utkan u identitet grada da postoji stara izreka: ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"„Nisi muško ako ne znaš plesati Morešku.\"","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Taj osjećaj pripadnosti počinje rano. Dječaci ovdje uče korake već u ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"osnovnoj školi","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", a ulazak u družinu doživljava se kao znak zrelosti i građanskog ponosa. Uloge, uključujući kraljeve i Bulu, često se predaju kroz naraštaje, s oca na sina. Kada gledate izvedbu, vrlo je moguće da gledate nekoga tko čini upravo ono što su njegov otac i djed činili na istoj pozornici.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Što je potrebno da postanete moreškant","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Moreška izgleda uzbudljivo jer to uistinu i jest, zahtjevna. Uvježbavanje se usredotočuje na troje:","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"list","listType":"bullet","start":1,"tag":"ul","version":1,"children":[{"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Vještina mačevanja.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" Svaki plesač barata s ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"dvama","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" željeznim oštricama, desna ruka udara, lijeva pariraju, u tehnici dvaju mačeva koja Morešku razlikuje od svakog drugog europskog plesa s mačevima. Mačevi su pravi, teški oko kilogram svaki.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Izdržljivost.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" Ples je intenzivan kardiovaskularni napor. Plesači održavaju borbu visoke energije kroz cijeli niz od sedam sve žešćih sukoba, fizički iscrpljujuće, osobito po ljetnoj vrućini.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Vremenski sklad i preciznost.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" Upravo to razlikuje moreškanta od nekoga tko tek maše mačem. Oštrice se moraju sudarati ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"snažno","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", dovoljno da iskre i da zadovolje estetiku pravoga ratnog plesa, a opet dovoljno precizno da nitko ne strada. Ta ravnoteža dolazi s mjesecima predane vježbe, otprilike od deset mjeseci do godinu i pol dana da se izađe na pozornicu.","type":"text","version":1}]}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Zato onaj ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"bam, bam, bam","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" mačeva zvuči toliko uvjerljivo. Nije to koreografija odglumljena na sigurnoj udaljenosti, nego kontrolirano željezo u punom dodiru, koje izvode ljudi koji su za to naporno vježbali i odrasli uz ovu tradiciju.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Ljudi iza plesa, nekad i sad","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Moreška je opstala jer su je pojedinci odlučili nositi. Imena koja su je spasila pamte se u Korčuli:","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"list","listType":"bullet","start":1,"tag":"ul","version":1,"children":[{"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Ivo Lozica","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", gradski brijač, predvodio je poslijeratnu obnovu 1944. i pamti se kao „neumorni duh\".","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Božo Jeričević","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", učitelj, od nule je uvježbao tu prvu poslijeratnu skupinu tinejdžera, u dobi od svega 12 do 17 godina, nakon što je rat raznio nošnje, mačeve i partiture.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Krsto Odak","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" i dirigent ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Josip Svoboda","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" dali su plesu partituru za limenu glazbu, napisanu 1937., koja i danas pokreće svaku izvedbu.","type":"text","version":1}]}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Danas tradiciju nosi društvo od oko ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"150 članova","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", ustrojeno u ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"moreškantsku družinu","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/sections/wind-orchestra"},"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Puhački orkestar","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":" i ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/sections/klapa"},"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Klapu Sveta Cecilija","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":". Plesači koje vidite na pozornici trenutačna su karika u lancu koji se neprekinuto proteže sve do njih.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Njihovim riječima","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"quote","version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"⚠️ UREDNIK / HGD: ovaj je odjeljak namjerno ostavljen kao predložak, popunite ga stvarnim intervjuima prije objave. Ne izmišljajte citate, imena ni životopise.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":"  Predloženi okviri koji bi posta učinili živim (i pogodnim za dijeljenje):  - ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"[[IME PLESAČA]]","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", koliko ste imali godina kad ste prvi put plesali? Tko vas je učio? ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"(citat od 2–3 rečenice + fotografija)","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" - ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"[[OTAC I SIN / VIŠEGENERACIJSKI PAR]]","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", obitelj koja pleše kroz naraštaje. ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"(citat + fotografija)","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" - ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"[[BULA / KRALJ]]","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", kako je igrati glavnu ulogu. ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"(citat + fotografija)","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" - ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"[[NAJMLAĐI PLESAČ]]","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", tinejdžer na početku puta. ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"(citat + fotografija)","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" - Jedna rečenica o tome ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"koliko nastupa","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" plesač odradi u sezoni i ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"kako izgleda vježbanje","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" iz tjedna u tjedan.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Upravo taj odjeljak dobar post pretvara u pamtljiv i ljudski, i upravo je to građa koja dobro prolazi pri dijeljenju. Samo mora biti stvarna, prikupljena od same družine.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Nositi je dalje","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Svaki sudar željeza na pozornici Ljetnoga kina najnoviji je redak priče koja se priča stoljećima. Moreškanti ne rekreiraju povijest za publiku, oni ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"jesu","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" ta povijest, još uvijek živa, još uvijek u vježbi, još uvijek predaje mačeve sljedećem naraštaju korčulanskih sinova.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Želite ih vidjeti na djelu? Pročitajte ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/blog/what-to-expect-moreska-performance-korcula"},"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"što očekivati na nastupu","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":" ili saznajte više ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/about"},"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"o HGD Sveta Cecilija","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":", društvu koje ovaj ples održava živim od 1883.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/tickets"},"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Pogledajte moreškante ove sezone, kupite ulaznice →","type":"text","version":1}],"direction":"ltr","format":"","indent":0}]}]}}'::jsonb,
  '2026-12-15T09:00:00Z'::timestamptz, 'draft'::enum_posts_status
WHERE NOT EXISTS (SELECT 1 FROM posts WHERE slug = 'iza-kulisa-moreskanti' AND locale = 'hr');

INSERT INTO posts (title, slug, locale, excerpt, hero_image, hero_image_alt, body, published_at, status)
SELECT 'Behind the Scenes: Meet the Moreška Dancers', 'behind-the-scenes-moreska-dancers', 'en'::enum_posts_locale, 'Who are the people behind Korčula''s sword dance? Meet the moreškanti, the dancers who train intensively, wield real iron, and carry a 400-year tradition forward.',
  '/moreskanti-cool.webp', 'Moreška dancers (moreškanti) in full costume in Korčula', '{"root":{"direction":"ltr","format":"","indent":0,"type":"root","version":1,"children":[{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"When you watch the Moreška, you see two armies, fourteen flashing swords and a story of love and combat. What you don''t see is everything behind it: the months of training, the family lines, and the quiet pride of a community that has handed this dance from one generation to the next for centuries. Meet the ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"moreškanti","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", the people who keep Korčula''s sword dance alive.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Not actors, Korčulans","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The first thing to understand is that the Moreška isn''t performed by a touring cast. It''s performed by the people of Korčula. The dance has traditionally been the domain of local men from Korčulan families, and it''s woven so deeply into the town''s identity that there''s an old local saying: ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"\"You are not a man if you cannot dance Moreška.\"","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"That sense of belonging starts young. Boys here begin learning the steps in ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"elementary school","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", and stepping into the troupe is seen as a marker of adulthood and civic pride. Roles, including the kings and the Bula, are often passed down through families across generations. When you watch a performance, you may well be watching someone do exactly what their father and grandfather did on the same stage.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"What it takes to be a moreškant","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Moreška looks thrilling because it genuinely is demanding. The training focuses on three things:","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"list","listType":"bullet","start":1,"tag":"ul","version":1,"children":[{"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Swordsmanship.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" Each dancer wields ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"two","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" iron blades, the right hand strikes, the left parries, in the double-sword technique that sets the Moreška apart from every other European sword dance. The swords are real, weighing about a kilogram each.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Stamina.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" The dance is an intense cardiovascular workout. Dancers sustain high-energy combat for the full sequence of seven escalating battles, physically grueling, especially in the summer heat.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Timing and precision.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" This is the part that separates a moreškant from someone simply swinging a sword. The blades have to clash ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"hard","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", hard enough to spark and to satisfy the aesthetics of a real war dance, while striking precisely enough that no one gets hurt. That balance comes from months of dedicated practice, roughly ten months to a year and a half to become stage-ready.","type":"text","version":1}]}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"It''s why the ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"bam, bam, bam","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" of the swords sounds so convincing. It isn''t choreography mimed at a safe distance; it''s controlled, full-contact iron, performed by people who have trained hard for it and grown up with the tradition.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The people behind the dance, past and present","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"The Moreška has survived because individuals chose to carry it. The names that saved it are remembered in Korčula:","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"list","listType":"bullet","start":1,"tag":"ul","version":1,"children":[{"direction":"ltr","format":"","indent":0,"type":"listitem","value":1,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Ivo Lozica","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", the town barber, led the post-war revival of 1944 and is remembered as an \"indefatigable spirit.\"","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":2,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Božo Jeričević","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", a schoolteacher, trained that first post-war troop of teenagers, aged just 12 to 17, from scratch, after the war had scattered the costumes, swords and scores.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"listitem","value":3,"version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Krsto Odak","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" and conductor ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Josip Svoboda","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" gave the dance the brass-band score, written in 1937, that still drives every performance.","type":"text","version":1}]}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Today the tradition is carried by a society of around ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"150 members","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", organised into the ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"Moreška Troop","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", the ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/sections/wind-orchestra"},"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Wind Orchestra","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":", and ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/sections/klapa"},"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Klapa Sveta Cecilija","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":". The dancers you see on stage are the current link in a chain that runs unbroken back through all of them.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"In their own words","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"quote","version":1,"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"⚠️ EDITOR / HGD: this section is intentionally left as a template, fill it with real interviews before publishing. Do not invent quotes, names, or biographies.","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":"  Suggested slots to make this post sing (and shareable on social):  - ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"[[DANCER NAME]]","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", how old were you when you first danced? Who taught you? ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"(2–3 sentence quote + photo)","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" - ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"[[A FATHER-AND-SON / MULTI-GENERATION PAIR]]","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", a family that''s danced across generations. ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"(quote + photo)","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" - ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"[[THE BULA / A KING]]","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", what it feels like to play a lead role. ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"(quote + photo)","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" - ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"[[A YOUNGEST DANCER]]","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":", a teenager just starting out. ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"(quote + photo)","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" - One sentence on ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"how many performances","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" a dancer might do in a season, and ","type":"text","version":1},{"detail":0,"format":1,"mode":"normal","style":"","text":"what training looks like","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" week to week.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"This is the section that turns a good post into a memorable, human one, and it''s exactly the material that performs well when shared. It just has to be real, gathered from the troupe itself.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"heading","tag":"h2","version":1,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Carrying it forward","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Every clash of iron on the Summer Cinema stage is the latest line in a story that''s been told for centuries. The moreškanti aren''t re-creating history for an audience, they ","type":"text","version":1},{"detail":0,"format":2,"mode":"normal","style":"","text":"are","type":"text","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":" the history, still living, still training, still passing the swords to the next generation of Korčula''s sons.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Want to see them in action? Read ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/blog/what-to-expect-moreska-performance-korcula"},"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"what to expect at a performance","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":", or learn more ","type":"text","version":1},{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/about"},"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"about HGD Sveta Cecilija","type":"text","version":1}],"direction":"ltr","format":"","indent":0},{"detail":0,"format":0,"mode":"normal","style":"","text":", the society that has kept this dance alive since 1883.","type":"text","version":1}]},{"direction":"ltr","format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"children":[{"type":"link","version":3,"fields":{"linkType":"custom","newTab":false,"url":"/tickets"},"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"See the moreškanti perform this season, book tickets →","type":"text","version":1}],"direction":"ltr","format":"","indent":0}]}]}}'::jsonb,
